// Pastikan folder files ada
if (!is_dir("files")) {
    mkdir("files", 0777, true);
}

// Function untuk rename file dalam array JSON
function processFiles(&$values, $key, $prefix) {
    if (!isset($values[$key])) return;

    $fileArray = json_decode($values[$key], true);
    if (json_last_error() !== JSON_ERROR_NONE) {
        error_log("JSON decode error: " . json_last_error_msg());
        return;
    }

    for ($i = 0; $i < count($fileArray); $i++) {
        if (isset($fileArray[$i]["usrName"])) {
            $fileArray[$i]["usrName"] = strtolower($fileArray[$i]["usrName"]);
        }
    }

    $values[$key] = json_encode($fileArray);

    $fileArray = json_decode($values[$key], true);
    if (json_last_error() !== JSON_ERROR_NONE) {
        error_log("JSON decode error: " . json_last_error_msg());
        return;
    }

    for ($i = 0; $i < count($fileArray); $i++) {
        if (!isset($fileArray[$i]["name"])) continue;

        $fileName = $fileArray[$i]["name"];
        $newFileName = "files/" . $prefix . "_" . $values["nama_madrasah"] .".pdf";

        if (file_exists($fileName)) {
            rename($fileName, getabspath($newFileName));
            $fileArray[$i]["name"] = $newFileName;
        } else {
            error_log("File $fileName tidak ditemukan.");
        }
    }

    $values[$key] = json_encode($fileArray);
}

// Proses file untuk "izop kanwil" dan "upload scan"
processFiles($values, "file_pertinggal", "file_pertinggal");


return true;
